def analyze_scores(scores):
    if not scores:
        return {
            'average_score': 0
            'highest_score': 0
            'lowest_score': 0
            'passed': 0
            'failed': 0
        }
    total = sum(scores)
    count = len(scores)
    avg = total / count
    high = max(scores)
    low = min(scores)
    passed_count = 0
    failed_count = 0
    for score in scores:
        if score >= 60:
            passed_count += 1
        else:
            failed_count += 1
    return {
        'average_score': avg
        'highest_score': high
        'lowest_score': low
        'passed': passed_count
        'failed': failed_count
    }
